import { useState } from 'react';

const faqs = [
  {
    question: 'L\'assurance décennale est-elle obligatoire pour un électricien ?',
    answer: 'Oui, l\'assurance décennale est obligatoire pour tout électricien qui réalise des travaux de construction selon la loi Spinetta (1978). Sans cette assurance, vous ne pouvez pas exercer légalement et risquez des sanctions pénales en cas de sinistre.'
  },
  {
    question: 'Quel est le prix moyen d\'une assurance décennale pour électricien ?',
    answer: 'Le prix varie selon votre statut : auto-entrepreneur (600-900€/an), artisan (1000-2000€/an), société (sur devis). Le tarif dépend aussi de votre chiffre d\'affaires, votre expérience et les garanties souhaitées.'
  },
  {
    question: 'Que se passe-t-il après 8 ans ?',
    answer: 'Après 8 ans, la garantie décennale prend fin pour les travaux nuevos. Cependant, les dommages révélés avant la fin de la 10ème année sont toujours couverts. Passé ce délai, seul subsiste la garantie RC Pro pour les dommages en cours.'
  },
  {
    question: 'Quelle est la différence entre RC Pro et décennale ?',
    answer: 'La RC Pro (Responsabilité Civile Professionnelle) couvre les dommages causés pendant les travaux. La garantie décennale couvre les défauts de construction qui apparaissent après réception des travaux pendant 10 ans.'
  },
  {
    question: 'Un auto-entrepreneur doit-il avoir une assurance décennale ?',
    answer: 'Oui, même en statut auto-entrepreneur, l\'assurance décennale est obligatoire si vous réalisez des travaux de construction. Cela inclut les travaux électriques neufs, rénovation et installation.'
  },
  {
    question: 'Que couvre l\'assurance décennale pour électricien ?',
    answer: 'Elle couvre les dommages liés à votre intervention électrique : défaut d\'installation, masalah de câblage, tableau électrique défectueux, court-circuit, incendie d\'origine électrique, et dommages aux tiers.'
  }
];

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState(null);

  return (
    <section id="faq" className="py-12 md:py-20 bg-gray-50">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10 md:mb-14">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-900">
            Questions <span className="text-yellow-600">fréquentes</span>
          </h2>
          <p className="mt-3 sm:mt-4 text-gray-600 text-base md:text-lg">
            Tout ce que vous devez savoir sur l'assurance décennale pour électricien
          </p>
        </div>

        <div className="space-y-3 sm:space-y-4">
          {faqs.map((faq, index) => (
            <div key={index} className="bg-white rounded-xl shadow-sm overflow-hidden">
              <button
                className="w-full px-4 sm:px-6 py-4 sm:py-5 text-left flex items-center justify-between"
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
              >
                <span className="font-semibold text-gray-900 pr-3 sm:pr-4 text-sm sm:text-base">{faq.question}</span>
                <span className={`text-lg sm:text-2xl text-yellow-600 transition-transform flex-shrink-0 ml-2 ${openIndex === index ? 'rotate-180' : ''}`}>
                  ▼
                </span>
              </button>
              {openIndex === index && (
                <div className="px-4 sm:px-6 pb-4 sm:pb-5 text-gray-600 text-sm sm:text-base">
                  {faq.answer}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
